  `recommendedAccessLevel` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `culturalSensitivity` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `culturalNotes` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
